#include<bits/stdc++.h>
using namespace std;
bool vis[200010];
int col[200010],cnt;
vector<int> mp[200010];
bool can=false;
void dfs(int x,int flag=0,int fa=-1)
{
    cnt++;
    vis[x]=true;
    for(int i:mp[x])
    {
        if(vis[i]&&i!=fa)
        {
            can=true;
            flag=1;
        }
    }
    for(int i:mp[x])
    {
        if(!vis[i])
        {
            dfs(i,flag,x);
        }
    }
    col[x]=flag;
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        cnt=0;
        int n,m;
        scanf("%d%d",&n,&m);
        for(int i=1;i<=n;i++)
        {
            col[i]=0;
            vis[i]=false;
            mp[i].clear();
        }
        for(int i=1;i<=m;i++)
        {
            int x,y;
            scanf("%d%d",&x,&y);
            mp[x].push_back(y);
            mp[y].push_back(x);
        }
        can=false;
        dfs(1);
        if(!can||cnt!=n)
        {
            printf("-1\n");
        }
        else
        {
            for(int i=1;i<=n;i++)
            {
                if(col[i]==0)
                {
                    printf("W");
                }
                else
                {
                    printf("B");
                }
            }
            printf("\n");
        }
    }
    return 0;
}
